mapper.select:
SELECT t.id, t.type, t.amount, t.occurred_at, t.category_id, c.name AS category_name, t.account_id, a.name AS account_name, t.note FROM transactions t INNER JOIN categories c ON c.id = t.category_id INNER JOIN accounts a ON a.id = t.account_id WHERE t.user_id = #{userId}
AND t.type = #{type}
AND t.occurred_at >= #{startAt}
AND t.occurred_at < #{endAt}
AND t.category_id = #{categoryId}
AND t.account_id = #{accountId}
AND (t.note LIKE CONCAT('%', #{keyword}, '%') OR c.name LIKE CONCAT('%', #{keyword}, '%') OR a.name LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY t.occurred_at DESC, t.id DESC
